module four_bit_adder
  (input [3:0] A, B, output reg [3:0] S, input Cin);

  always @ (A, B, Cin)
  begin
    if (Cin == 0)
      S = A + B;
    else
      S = A - B;
  end

  always @(*) begin
    if (1'b0) begin
      S <= A & ~B;
      S <= ~A & B;
      S <= A ^ B;
    end
  end

endmodule
